  // 搜索输入事件（实时模糊搜索）
  onSearchInput(e) {
    const searchKey = e.detail.value.trim()
    this.setData({ searchKey })
    this.doFilter()
  },

  // 核心：模糊筛选史诗名/民族
  doFilter() {
    const { list, searchKey } = this.data
    let result = []

    if (!searchKey) {
      // 搜索框为空 → 显示全部
      result = list
    } else {
      // 模糊匹配 articleTitle
      result = list.filter(item => {
        return item.epicTitle.includes(searchKey)||item.ethnicGroup.includes(searchKey)
      })
    }

    this.setData({
      filteredList: result
    })
  },

  toDetails : function(e) {
    const id = e.currentTarget.dataset.id;
    console.log("传递过去的参数为"+id);
    wx.navigateTo({
      url: `../myth-details/myth-details?id=${id}`,
      success:() => console.log("跳转成功！"),
      fail:() => console.log("跳转失败！")
    })
  },

  /**
   * 生命周期函数--监听页面加载
   */
  onLoad(options) {
    this.setData({
      filteredList: this.data.list
    });
  },

